import React from "react";

const COLORS = {
  red: "#B80000",
  gold: "#D4A017",
  white: "#FFFFFF",
  lightGray: "#F4F4F4",
  darkText: "#222222",
};

function App() {
  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        backgroundColor: COLORS.lightGray,
        fontFamily: "Arial, sans-serif",
      }}
    >
      {/* HEADER */}
      <header
        style={{
          backgroundColor: COLORS.white,
          borderBottom: `3px solid ${COLORS.red}`,
          padding: "1rem 2rem",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <div
          style={{
            fontWeight: "bold",
            fontSize: "1.4rem",
            color: COLORS.red,
          }}
        >
          BALBOA ALERTA
        </div>
        <div
          style={{
            fontSize: "0.9rem",
            color: COLORS.darkText,
            borderLeft: `3px solid ${COLORS.gold}`,
            paddingLeft: "0.7rem",
          }}
        >
          Plataforma ciudadana de reportes locales
        </div>
      </header>

      {/* CONTENIDO PRINCIPAL */}
      <main
        style={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          textAlign: "center",
          padding: "2rem 1rem",
        }}
      >
        <h1
          style={{
            color: COLORS.red,
            fontSize: "2.4rem",
            marginBottom: "0.5rem",
          }}
        >
          ¡BALBOA ALERTA ESTÁ VIVO!
        </h1>

        <p
          style={{
            color: COLORS.darkText,
            maxWidth: "520px",
            fontSize: "1rem",
            marginBottom: "2rem",
          }}
        >
          Vecinos organizados reportando basura, daños, riesgos y problemas en
          tiempo real. Un distrito más limpio, más seguro, más nuestro.
        </p>

        <button
          style={{
            padding: "1rem 2.5rem",
            fontSize: "1.2rem",
            fontWeight: "bold",
            borderRadius: "999px",
            border: "none",
            backgroundColor: COLORS.red,
            color: COLORS.white,
            cursor: "pointer",
            boxShadow: "0 4px 10px rgba(0,0,0,0.15)",
          }}
          onClick={() => alert("Aquí irá el formulario de reporte")}
        >
          Reportar incidencia
        </button>
      </main>

      {/* FOOTER */}
      <footer
        style={{
          backgroundColor: COLORS.white,
          borderTop: `2px solid ${COLORS.gold}`,
          padding: "0.7rem 1.5rem",
          fontSize: "0.8rem",
          color: COLORS.darkText,
          textAlign: "center",
        }}
      >
        Balboa Alerta · Iniciativa ciudadana para La Chorrera
      </footer>
    </div>
  );
}

export default App;
